/**
 * @summary List transactions
 */
export const getListTransactionsUrl = (params?: ListTransactionsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/wallet/transactions?${stringifiedParams}`
    : `/api/wallet/transactions`;
};

export const listTransactions = async (
  params?: ListTransactionsParams,
  options?: RequestInit,
): Promise<TransactionsListResponse> => {
  return customFetch<TransactionsListResponse>(getListTransactionsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListTransactionsQueryKey = (
  params?: ListTransactionsParams,
) => {
  return [`/api/wallet/transactions`, ...(params ? [params] : [])] as const;
};

